@register_tool(
    "get_epic",
    schema=GET_EPIC_SCHEMA,
    operation_kind="read",
)
def get_epic(
    context: ToolContext,
    epic_id: str,
    sections: list[str] | None = None,
) -> JSONDict:
    epic = context.store.load_epic(epic_id)
